import{_ as a,o as n,c as t,ae as i}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"Journeys Assist Implementation","description":"","frontmatter":{"title":"Journeys Assist Implementation","slug":"implement-journeys-assist"},"headers":[],"relativePath":"developer-hub/implement-journeys-assist.md","filePath":"developer-hub/implement-journeys-assist.md"}'),s={name:"developer-hub/implement-journeys-assist.md"};function o(r,e,l,h,d,p){return n(),t("div",null,[...e[0]||(e[0]=[i(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Journeys Assist allows you to combine your powerful banners and interstitials from <a href="./journeys-overview.html">Journeys</a> with your mobile measurement capabilities of <a href="./ads-overview.html">Ads</a>, <a href="./branch-universal-email.html">Email</a> and other Branch-powered channels to provide complete attribution of the user flow.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p><strong>Same Session</strong> (Enabled by default)</p><ol><li><p>User lands on your mobile website and sees a banner or full-page interstitial promoting the mobile app coming from an ad, email interaction or other Branch powered channel.</p><ul><li>User can come from an ad they interact with (click).</li><li>User can come from an email campaign (click).</li></ul></li><li><p>User clicks the call to action to install the mobile app within the same session.</p></li><li><p>Once the user opens the app, conversions (including the install) that happen in the app, are attributed to the original Branch powered campaign the user interacted with.</p></li></ol><p><strong>Multi Session</strong></p><ol><li><p>User lands on your mobile website and sees a banner or full-page interstitial promoting the mobile app coming from an ad, email interaction or other Branch powered channel.</p><ul><li>User can come from an ad they interact with (click).</li><li>User can come from an email campaign (click).</li></ul></li><li><p>User drops off for some time and returns to the mobile website to see the Journeys banner/interstitial again.</p></li><li><p>User clicks the call to action to install the mobile app.</p></li><li><p>Once the user opens the app, conversions (including the install) that happen in the app, are attributed to the original Branch powered campaign the user interacted with.</p></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Journeys Assist, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Enabled Journeys for your Branch account.</p><ul><li>Contact your Branch account manager or visit <a href="https://branch.io/pricing" target="_blank" rel="noreferrer">https://branch.io/pricing</a></li></ul></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Implemented the Branch <a href="./web-sdk-overview.html">Web SDK</a> into your website.</p></li><li><p>Already running Journeys <a href="./create-journey-banner-or-interstitial.html">banners/interstitials</a>.</p></li><li><p>Already running other Branch powered channels, like ad campaigns through your chosen <a href="./ad-partners-list.html">ad partner</a> and/or running email campaigns through your chosen <a href="./email-partners-list.html">email partner</a>.</p></li></ol><h2 id="enabling-journeys-assist" tabindex="-1">Enabling Journeys Assist <a class="header-anchor" href="#enabling-journeys-assist" aria-label="Permalink to &quot;Enabling Journeys Assist&quot;">​</a></h2><h3 id="same-session" tabindex="-1"><strong>Same Session</strong> <a class="header-anchor" href="#same-session" aria-label="Permalink to &quot;**Same Session**&quot;">​</a></h3><p>This is enabled by default for all Journeys. If a user is driven to a mobile web session from a Branch powered channel and interacts with a Journey Banner within the same session, Branch will automatically bypass the Journey CTA link with the session&#39;s referring Branch Link.</p><h3 id="multi-session" tabindex="-1"><strong>Multi Session</strong> <a class="header-anchor" href="#multi-session" aria-label="Permalink to &quot;**Multi Session**&quot;">​</a></h3><p>If you wish to support Journeys Assist across multiple mobile web sessions to credit referring Branch powered channels for longer durations, you must add two new parameters the web SDKs initialization options.</p><table tabindex="0"><thead><tr><th>Key</th><th>Value</th><th>Definition</th></tr></thead><tbody><tr><td>enableExtendedJourneysAssist</td><td>Boolean</td><td>Enable or Disable Multi Session Journeys Assist. <strong>Branch defaults to false</strong></td></tr><tr><td>extendedJourneysAssistExpiryTime</td><td>Timestamp</td><td>TTL value in milliseconds for the referring Branch Link. <strong>Branch recommends and defaults to 7 days</strong></td></tr></tbody></table><h4 id="opt-in-to-journeys-assist-multi-session-through-web-sdk-initialization-options" tabindex="-1">Opt-In to Journeys Assist Multi Session through Web SDK Initialization Options <a class="header-anchor" href="#opt-in-to-journeys-assist-multi-session-through-web-sdk-initialization-options" aria-label="Permalink to &quot;Opt-In to Journeys Assist Multi Session through Web SDK Initialization Options&quot;">​</a></h4><p>Before the Branch SDK initializes, implement the following method:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>var options = { </span></span>
<span class="line"><span>  enableExtendedJourneysAssist: true, // enable or disable referring Branch link expiry for Journeys Assist</span></span>
<span class="line"><span>  extendedJourneysAssistExpiryTime : 5000 // TTL value in milliseconds for the referring Branch link. Defaults to 7 days</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span>branch.init(&#39;key_live_YOUR_KEY_GOES_HERE&#39;, options, function(err, data) {</span></span>
<span class="line"><span>  console.log(err, data);</span></span>
<span class="line"><span>});</span></span></code></pre></div><h2 id="disabling-journeys-assist" tabindex="-1">Disabling Journeys Assist <a class="header-anchor" href="#disabling-journeys-assist" aria-label="Permalink to &quot;Disabling Journeys Assist&quot;">​</a></h2><p>If you wish to disable the default Same Session Journeys Assist support and have Journeys always claim attribution for post CTA click conversions, you can do so through the following two ways:</p><h4 id="_1-add-make-new-link-true-to-your-journey-view-deep-link-data" tabindex="-1">1. Add <code>make_new_link:true</code> to your Journey View Deep Link Data <a class="header-anchor" href="#_1-add-make-new-link-true-to-your-journey-view-deep-link-data" aria-label="Permalink to &quot;1. Add \`make_new_link:true\` to your Journey View Deep Link Data&quot;">​</a></h4><h4 id="_2-add-make-new-link-true-to-the-web-sdk-initialization-options" tabindex="-1">2. Add <code>make_new_link:true</code> to the web SDK initialization options <a class="header-anchor" href="#_2-add-make-new-link-true-to-the-web-sdk-initialization-options" aria-label="Permalink to &quot;2. Add \`make_new_link:true\` to the web SDK initialization options&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>var options = { </span></span>
<span class="line"><span>  make_new_link: true</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span>branch.init(&#39;key_live_YOUR_KEY_GOES_HERE&#39;, options, function(err, data) {</span></span>
<span class="line"><span>  console.log(err, data);</span></span>
<span class="line"><span>});</span></span></code></pre></div><h2 id="view-analytics" tabindex="-1">View Analytics <a class="header-anchor" href="#view-analytics" aria-label="Permalink to &quot;View Analytics&quot;">​</a></h2><p>After enabling Journeys Assist and as campaigns run, your ad/email campaigns should receive credit through Journeys installs and other conversions. To do this, we can apply the add the <code>~tags</code> filter for your respective campaign. With this, you can view which Journeys campaign drove the ad/email conversion.</p><table tabindex="0"><thead><tr><th></th><th>Key</th><th>Value</th></tr></thead><tbody><tr><td>Dashboard Report Filter</td><td>tags</td><td>The view/creative name of your Journeys campaign.</td></tr><tr><td>Exports Key</td><td>Last Attributed Touch Data Tilde Journey Name</td><td>The view/creative name of your Journeys campaign.</td></tr></tbody></table><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>Does Journeys Assist work with all types of ad networks?</summary><p>Journeys Assist only works with ad networks where a Branch Link is used for redirection. In other words, ad networks that solely rely on an MMP API connection to function will not utilize Journeys Assist.</p></details>`,29)])])}const m=a(s,[["render",o]]);export{c as __pageData,m as default};
